using System.Net;
using Microsoft.AspNetCore.HttpOverrides;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();
// Fixed: Singleton capturing scoped service causes ValidateScopes failure in .NET 9 dev mode.
// Changed to Scoped so it respects the IUserService lifetime.
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));
// Fixed: .NET 9 HttpClientFactory uses SocketsHttpHandler by default;
// casting to HttpClientHandler throws InvalidCastException.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() => new HttpClientHandler { UseCookies = false });
// Fixed: .NET 9 HttpClientFactory redacts all header values in Trace-level logs by default.
// Allowlist non-sensitive headers needed for debugging.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(h =>
        h != "X-Forwarded-For" && h != "X-Forwarded-Proto" && h != "X-Request-Id"));
// Fixed: .NET 9 ForwardedHeadersMiddleware ignores X-Forwarded-* from unknown proxies.
// Configure KnownNetworks to trust the reverse proxy subnet.
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    options.KnownNetworks.Add(new Microsoft.AspNetCore.HttpOverrides.IPNetwork(IPAddress.Parse("10.0.0.0"), 8));
});
var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

